### Reverse
```cpp
void reverse() {
	Node<T>* next = nullptr;
	Node<T>* curr = head;
	Node<T>* prev = nullptr;
	
	while(curr) {
		next = curr->next;
		curr->next = prev;
		prev = curr;
		curr = next;
	}
	
	head = prev;
}
```

---
### Find
```cpp
Node<T>* find(T item) {
	Node<T>* curr = head;
	while(curr) {
		if(curr->data == item) return curr;
		curr = curr->data;
	}
	return nullptr;
}
```

